const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

// Find qualifying workshops in CO with basePrice <= 80
const qualifyingEvents = events.filter(e => {
  if (!e) return false;
  if (e.eventType !== 'workshops') return false;
  if (e.workshopType !== 'Lead Climbing Safety') return false;
  if (e.state !== 'CO') return false;
  if (typeof e.basePrice !== 'number') return false;
  return e.basePrice <= 80;
});

let targetEvent = null;
if (qualifyingEvents.length > 0) {
  targetEvent = qualifyingEvents.slice().sort((a, b) => {
    const ta = a.startDateTime ? new Date(a.startDateTime).getTime() : Infinity;
    const tb = b.startDateTime ? new Date(b.startDateTime).getTime() : Infinity;
    return ta - tb;
  })[0];
}

let qualifyingRegistrations = [];
if (targetEvent) {
  qualifyingRegistrations = regs.filter(r => {
    if (!r || r.eventId !== targetEvent.id) return false;
    const price = typeof r.registrationTierPrice === 'number' ? r.registrationTierPrice : null;
    return price !== null && price <= 80;
  });
}

// Single checkpoint: user has at least one qualifying registration for the correct earliest event at price <= 80
checkpoints.push({ passed: targetEvent != null && qualifyingRegistrations.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('membership_plans') || '[]');
const purchases = JSON.parse(localStorage.getItem('membership_purchases') || '[]');

// Identify qualifying routesetter membership terms: active, individual, routesetter-focused, 12 months, price < 120
const qualifyingTerms = [];
plans.forEach(p => {
  if (!p) return;
  if (p.category !== 'individual') return;
  if (p.status !== 'active') return;
  const name = (p.name || '').toLowerCase();
  const code = (p.code || '').toLowerCase();
  const isRoutesetterPlan = name.includes('routesetter') || code.includes('routesetter');
  if (!isRoutesetterPlan) return;
  const terms = Array.isArray(p.availableTerms) ? p.availableTerms : [];
  terms.forEach(t => {
    if (!t) return;
    if (t.durationMonths !== 12) return;
    if (typeof t.price !== 'number' || t.price >= 120) return;
    qualifyingTerms.push({ planId: p.id, term: t });
  });
});

let targetPlanIds = new Set();
let maxPriceThreshold = 120;
qualifyingTerms.forEach(qt => {
  targetPlanIds.add(qt.planId);
});

// Find purchases that match any qualifying routesetter plan with 12-month duration, price < 120, autoRenew false, and paid
const qualifyingPurchases = purchases.filter(p => {
  if (!p) return false;
  if (!targetPlanIds.has(p.membershipPlanId)) return false;
  if (p.termDurationMonths !== 12) return false;
  if (typeof p.price !== 'number' || p.price >= maxPriceThreshold) return false;
  if (p.autoRenew !== false) return false;
  if (p.paymentStatus !== 'paid') return false;
  return true;
});

// Single checkpoint: at least one qualifying membership purchase meeting all criteria
checkpoints.push({ passed: targetPlanIds.size > 0 && qualifyingPurchases.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingList = Array.isArray(readingLists) && readingLists.length > 0 ? readingLists[0] : null;
const articleIds = readingList && Array.isArray(readingList.articleIds) ? readingList.articleIds : [];

const minDateMs = new Date('2023-01-01T00:00:00Z').getTime();

// Qualifying articles: advanced, tagged 'anchor building', publicationDate >= 2023-01-01
const qualifyingArticles = articles.filter(a => {
  if (!a) return false;
  if (a.skillLevel !== 'advanced') return false;
  const tags = Array.isArray(a.tags) ? a.tags : [];
  if (!tags.includes('anchor building')) return false;
  const t = a.publicationDate ? new Date(a.publicationDate).getTime() : NaN;
  if (isNaN(t)) return false;
  return t >= minDateMs;
});

const qualifyingById = {};
qualifyingArticles.forEach(a => { qualifyingById[a.id] = a; });

// Order of qualifying articles as they appear in the reading list (i.e., bookmark order)
const sequenceInList = articleIds
  .map(id => qualifyingById[id])
  .filter(a => !!a);

const countQualifyingBookmarked = sequenceInList.length;

// Expected most-recent-first order (top 3 by publicationDate desc)
const expectedOrderIds = qualifyingArticles
  .slice()
  .sort((a, b) => {
    const ta = a.publicationDate ? new Date(a.publicationDate).getTime() : 0;
    const tb = b.publicationDate ? new Date(b.publicationDate).getTime() : 0;
    return tb - ta;
  })
  .map(a => a.id);

let orderCorrect = false;
if (expectedOrderIds.length >= 3 && sequenceInList.length >= 3) {
  const firstThreeIds = sequenceInList.slice(0, 3).map(a => a.id);
  orderCorrect = firstThreeIds.every((id, idx) => id === expectedOrderIds[idx]);
}

// CP1-3: number of qualifying advanced anchor-building (2023+) articles actually bookmarked
checkpoints.push({ passed: countQualifyingBookmarked >= 1, weight: 0.25 });
checkpoints.push({ passed: countQualifyingBookmarked >= 2, weight: 0.25 });
checkpoints.push({ passed: countQualifyingBookmarked >= 3, weight: 0.25 });

// CP4: the first three qualifying bookmarks are in most-recent-first order
checkpoints.push({ passed: orderCorrect, weight: 0.25 });

return checklists = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const gyms = JSON.parse(localStorage.getItem('gyms') || '[]');
const favLists = JSON.parse(localStorage.getItem('favorite_gyms_lists') || '[]');
const favList = Array.isArray(favLists) && favLists.length > 0 ? favLists[0] : null;
const favGymIds = favList && Array.isArray(favList.gymIds) ? favList.gymIds : [];

// Qualifying gyms: in Colorado, with youth programs, within 20 miles (based on distanceFromSearchOrigin)
const qualifyingGyms = gyms.filter(g => {
  if (!g) return false;
  if (g.state !== 'CO') return false;
  if (g.hasYouthPrograms !== true) return false;
  const d = typeof g.distanceFromSearchOrigin === 'number' ? g.distanceFromSearchOrigin : Infinity;
  return d <= 20;
});

const sortedByDistance = qualifyingGyms.slice().sort((a, b) => {
  const da = typeof a.distanceFromSearchOrigin === 'number' ? a.distanceFromSearchOrigin : Infinity;
  const db = typeof b.distanceFromSearchOrigin === 'number' ? b.distanceFromSearchOrigin : Infinity;
  return da - db;
});

const targetTopTwo = sortedByDistance.slice(0, 2);
const targetIds = targetTopTwo.map(g => g.id);

const qualifyingFavorites = targetIds.filter(id => favGymIds.includes(id));

// CP1: at least one of the two closest qualifying gyms is in favorites
checkpoints.push({ passed: targetIds.length === 2 && qualifyingFavorites.length >= 1, weight: 0.5 });

// CP2: both of the two closest qualifying gyms are in favorites
checkpoints.push({ passed: targetIds.length === 2 && qualifyingFavorites.length === 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const jobs = JSON.parse(localStorage.getItem('job_postings') || '[]');
const profiles = JSON.parse(localStorage.getItem('saved_profiles') || '[]');
const apps = JSON.parse(localStorage.getItem('job_applications') || '[]');

// Qualifying jobs: head_routesetter, pacific region, salaryUnit per_year, salaryMin >= 55000
const qualifyingJobs = jobs.filter(j => {
  if (!j) return false;
  if (j.role !== 'head_routesetter') return false;
  if (j.region !== 'pacific') return false;
  if (j.salaryUnit !== 'per_year') return false;
  const minSalary = typeof j.salaryMin === 'number' ? j.salaryMin : null;
  if (minSalary === null || minSalary < 55000) return false;
  return true;
});

let targetJob = null;
if (qualifyingJobs.length > 0) {
  targetJob = qualifyingJobs.slice().sort((a, b) => {
    const ta = a.postedDate ? new Date(a.postedDate).getTime() : 0;
    const tb = b.postedDate ? new Date(b.postedDate).getTime() : 0;
    return tb - ta; // newest first
  })[0];
}

const profileIdSet = new Set((profiles || []).map(p => p.id));

let qualifyingApplications = [];
if (targetJob) {
  qualifyingApplications = apps.filter(a => {
    if (!a) return false;
    if (a.jobPostingId !== targetJob.id) return false;
    if (!profileIdSet.has(a.savedProfileId)) return false;
    return true;
  });
}

// Single checkpoint: at least one application using a saved profile to the correct newest qualifying job
checkpoints.push({ passed: targetJob != null && qualifyingApplications.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

// Helper: distance in miles between two lat/lon pairs
function distMiles(lat1, lon1, lat2, lon2) {
  if ([lat1, lon1, lat2, lon2].some(v => typeof v !== 'number')) return Infinity;
  const toRad = v => v * Math.PI / 180;
  const R = 3958.8;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const originLat = 47.6062; // Seattle
const originLon = -122.3321;
const mayStart = new Date('2025-05-01T00:00:00Z').getTime();
const juneStart = new Date('2025-06-01T00:00:00Z').getTime();

// Qualifying competitions: bouldering, in May 2025, within 100 miles of Seattle
const qualifyingEvents = events.filter(e => {
  if (!e) return false;
  if (e.eventType !== 'competitions') return false;
  if (e.discipline !== 'bouldering') return false;
  const t = e.startDateTime ? new Date(e.startDateTime).getTime() : NaN;
  if (isNaN(t) || t < mayStart || t >= juneStart) return false;
  const d = distMiles(originLat, originLon, e.latitude, e.longitude);
  if (d > 100) return false;
  if (typeof e.basePrice !== 'number') return false;
  return true;
});

let targetEvent = null;
if (qualifyingEvents.length > 0) {
  targetEvent = qualifyingEvents.slice().sort((a, b) => {
    const pa = typeof a.basePrice === 'number' ? a.basePrice : Infinity;
    const pb = typeof b.basePrice === 'number' ? b.basePrice : Infinity;
    if (pa !== pb) return pa - pb; // cheapest first
    const ta = a.startDateTime ? new Date(a.startDateTime).getTime() : Infinity;
    const tb = b.startDateTime ? new Date(b.startDateTime).getTime() : Infinity;
    return ta - tb;
  })[0];
}

let lowestTier = null;
if (targetEvent && Array.isArray(targetEvent.availableTiers) && targetEvent.availableTiers.length > 0) {
  lowestTier = targetEvent.availableTiers.reduce((minT, t) => {
    if (!t || typeof t.price !== 'number') return minT;
    if (!minT) return t;
    return t.price < minT.price ? t : minT;
  }, null);
}

let regsForTarget = [];
let regsYouthNoAddOns = [];
let regsYouthNoAddOnsLowestTier = [];

if (targetEvent) {
  regsForTarget = regs.filter(r => r && r.eventId === targetEvent.id);
  regsYouthNoAddOns = regsForTarget.filter(r => {
    const age = (r.ageCategory || '').toString().toLowerCase();
    const addOns = Array.isArray(r.selectedAddOns) ? r.selectedAddOns : [];
    return age === 'youth' && addOns.length === 0;
  });
  if (lowestTier) {
    regsYouthNoAddOnsLowestTier = regsYouthNoAddOns.filter(r => {
      const price = typeof r.registrationTierPrice === 'number' ? r.registrationTierPrice : null;
      const name = r.registrationTierName || '';
      return price === lowestTier.price && name === lowestTier.name;
    });
  }
}

// CP1 (0.4): Registered a youth participant with no add-ons for the correct cheapest qualifying event
checkpoints.push({ passed: targetEvent != null && regsYouthNoAddOns.length >= 1, weight: 0.4 });

// CP2 (0.6): That registration also used the lowest-priced registration tier
checkpoints.push({ passed: targetEvent != null && lowestTier != null && regsYouthNoAddOnsLowestTier.length >= 1, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const courses = JSON.parse(localStorage.getItem('courses') || '[]');
const enrollments = JSON.parse(localStorage.getItem('course_enrollments') || '[]');
const plans = JSON.parse(localStorage.getItem('learning_plans') || '[]');
const plan = Array.isArray(plans) && plans.length > 0 ? plans[0] : null;
const planCourseIds = plan && Array.isArray(plan.courseIds) ? plan.courseIds : [];

// Qualifying courses: level intermediate, durationWeeks < 8, rating >= 4.5
const qualifyingCourses = courses.filter(c => {
  if (!c) return false;
  if (c.level !== 'intermediate') return false;
  if (typeof c.durationWeeks !== 'number' || c.durationWeeks >= 8) return false;
  if (typeof c.rating !== 'number' || c.rating < 4.5) return false;
  return true;
});

let targetCourse = null;
if (qualifyingCourses.length > 0) {
  targetCourse = qualifyingCourses.slice().sort((a, b) => {
    const ra = typeof a.rating === 'number' ? a.rating : 0;
    const rb = typeof b.rating === 'number' ? b.rating : 0;
    if (rb !== ra) return rb - ra; // highest rating first
    const ca = typeof a.ratingCount === 'number' ? a.ratingCount : 0;
    const cb = typeof b.ratingCount === 'number' ? b.ratingCount : 0;
    return cb - ca; // tie-break by ratingCount
  })[0];
}

let enrolled = false;
let inPlan = false;

if (targetCourse) {
  enrolled = enrollments.some(e => e && e.courseId === targetCourse.id && e.status !== 'cancelled');
  inPlan = planCourseIds.includes(targetCourse.id);
}

// CP1 (0.4): Enrolled in the correct highest-rated qualifying intermediate course
checkpoints.push({ passed: targetCourse != null && enrolled, weight: 0.4 });

// CP2 (0.6): Enrolled in that course AND it is present in the learning plan
checkpoints.push({ passed: targetCourse != null && enrolled && inPlan, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const committees = JSON.parse(localStorage.getItem('committees') || '[]');
const submissions = JSON.parse(localStorage.getItem('volunteer_interest_submissions') || '[]');

// Qualifying committees: safety_standards, online, evenings, accepting volunteers
const qualifyingCommittees = committees.filter(c => {
  if (!c) return false;
  if (c.category !== 'safety_standards') return false;
  if (c.meetingFormat !== 'online') return false;
  if (c.meetingTime !== 'evenings') return false;
  if (c.isAcceptingVolunteers !== true) return false;
  return true;
});

const qualifyingCommitteeIds = new Set(qualifyingCommittees.map(c => c.id));

const qualifyingSubmissions = submissions.filter(s => {
  if (!s) return false;
  if (!qualifyingCommitteeIds.has(s.committeeId)) return false;
  const areas = Array.isArray(s.areasOfInterest) ? s.areasOfInterest.filter(v => !!v) : [];
  return areas.length >= 2;
});

// Single checkpoint: at least one qualifying volunteer interest submission
checkpoints.push({ passed: qualifyingCommitteeIds.size > 0 && qualifyingSubmissions.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
